import express from "express";
import mongoose from "mongoose";
import ReconciliationResult from "../models/ReconciliationResult.js";
import authMiddleware from "../middleware/auth.js";
import UploadJob from "../models/UploadJob.js";
import AuditTrail from "../models/AuditTrail.js";

const router = express.Router();

/**
 * 🟢 POST /api/reconcile/run
 */
router.post("/run", authMiddleware(["admin", "analyst"]), async (req, res) => {
  try {
    const uploadedRecords = Array.isArray(req.body?.uploadedRecords)
      ? req.body.uploadedRecords
      : [];
    const systemRecords = Array.isArray(req.body?.systemRecords)
      ? req.body.systemRecords
      : [];
    const rules = req.body?.rules || {};
    const results = [];

    const uploader =
      req.body?.uploadedBy && mongoose.Types.ObjectId.isValid(req.body.uploadedBy)
        ? req.body.uploadedBy
        : undefined;

    const newJob = await UploadJob.create({
      filename:
        req.body?.filename ||
        (uploadedRecords.length ? `uploaded_${Date.now()}` : "ManualRun"),
      ...(uploader ? { uploadedBy: uploader } : {}),
      status: "Processing",
      startedAt: new Date(),
    });

    // 🟡 No system records → unmatched
    if (systemRecords.length === 0) {
      const unmatched = uploadedRecords.map((u) => ({
        systemRecordId: null,
        uploadedRecordId:
          typeof u.transactionId === "string" ? u.transactionId.trim() : "N/A",
        status: "Unmatched",
        differences: { reason: "No system records available" },
      }));

      await ReconciliationResult.insertMany(
        unmatched.map((r) => ({ ...r, uploadJobId: newJob._id }))
      );
      await UploadJob.findByIdAndUpdate(newJob._id, {
        status: "Completed",
        reconciledCount: unmatched.length,
        completedAt: new Date(),
      });

      return res.json({
        message: "Reconciliation completed (no system records)",
        summary: unmatched,
        jobId: newJob._id,
      });
    }

    // 🟢 Detect duplicates
    const countMap = {};
    for (const rec of uploadedRecords) {
      const id =
        typeof rec.transactionId === "string"
          ? rec.transactionId.trim()
          : null;
      if (id) countMap[id] = (countMap[id] || 0) + 1;
    }
    const seen = new Set();

    // 🔁 Process each record
    for (const uploaded of uploadedRecords) {
      const txId =
        typeof uploaded.transactionId === "string"
          ? uploaded.transactionId.trim()
          : null;
      const uploadedAmount = Number(uploaded.amount);
      const ref =
        typeof uploaded.referenceNumber === "string"
          ? uploaded.referenceNumber.trim()
          : null;

      if (!txId || isNaN(uploadedAmount)) {
        results.push({
          systemRecordId: null,
          uploadedRecordId: txId || "N/A",
          status: "Unmatched",
          differences: { reason: "Missing transactionId or amount" },
        });
        continue;
      }

      if (countMap[txId] > 1 && seen.has(txId)) {
        results.push({
          systemRecordId: null,
          uploadedRecordId: txId,
          status: "Duplicate",
          differences: {},
        });
        continue;
      }
      seen.add(txId);

      const sysExact = systemRecords.find(
        (s) =>
          typeof s.transactionId === "string" &&
          s.transactionId.trim() === txId &&
          Math.abs(Number(s.amount) - uploadedAmount) < 0.0001
      );
      if (sysExact) {
        results.push({
          systemRecordId: sysExact.transactionId,
          uploadedRecordId: txId,
          status: "Matched",
          differences: {},
        });
        continue;
      }

      const variance =
        typeof rules.amountVariance === "number" ? rules.amountVariance : 0.2;
      const sysPartial = systemRecords.find((s) => {
        if (!s.referenceNumber || typeof s.referenceNumber !== "string" || !ref)
          return false;
        if (s.referenceNumber.trim() !== ref) return false;

        const sysAmt = Number(s.amount);
        if (isNaN(sysAmt) || sysAmt === 0) return false;

        const diff = Math.abs(sysAmt - uploadedAmount) / sysAmt;
        return diff > 0 && diff <= variance;
      });

      if (sysPartial) {
        results.push({
          systemRecordId: sysPartial.transactionId,
          uploadedRecordId: txId,
          status: "Partially Matched",
          differences: {
            amountDiff: uploadedAmount - Number(sysPartial.amount),
          },
        });
        continue;
      }

      results.push({
        systemRecordId: null,
        uploadedRecordId: txId,
        status: "Unmatched",
        differences: {},
      });
    }

    await ReconciliationResult.insertMany(
      results.map((r) => ({ ...r, uploadJobId: newJob._id }))
    );
    await UploadJob.findByIdAndUpdate(newJob._id, {
      status: "Completed",
      reconciledCount: results.length,
      completedAt: new Date(),
    });

    res.json({
      message: "Reconciliation completed",
      summary: results,
      jobId: newJob._id,
    });
  } catch (err) {
    console.error("Reconciliation error:", err);
    res.status(500).json({ message: "Reconciliation failed", error: err.message });
  }
});

/**
 * 🔹 GET /api/reconcile/summary
 */
router.get("/summary", authMiddleware(["admin", "analyst"]), async (req, res) => {
  try {
    const { jobId, status, uploadedBy, startDate, endDate } = req.query;

    const baseJob =
      jobId || (await UploadJob.findOne().sort({ createdAt: -1 }))?._id;
    if (!baseJob)
      return res.json({ message: "No reconciliation data found", summary: [] });

    const filter = { uploadJobId: baseJob };
    if (status && status !== "All") filter.status = status;

    if (startDate || endDate) {
      filter.createdAt = {};
      if (startDate)
        filter.createdAt.$gte = new Date(new Date(startDate).setHours(0, 0, 0));
      if (endDate)
        filter.createdAt.$lte = new Date(new Date(endDate).setHours(23, 59, 59));
    }

    let results = await ReconciliationResult.find(filter)
      .populate("uploadJobId")
      .sort({ createdAt: -1 });

    if (uploadedBy) {
      const search = uploadedBy.toLowerCase();
      results = results.filter((r) =>
        r.uploadJobId?.uploadedBy?.toString()?.toLowerCase()?.includes(search)
      );
    }

    res.json({ summary: results });
  } catch (err) {
    console.error("Summary fetch error:", err);
    res.status(500).json({ message: "Failed to fetch summary", error: err.message });
  }
});

/**
 * 🔹 GET /api/reconcile/history
 */
router.get("/history", authMiddleware(["admin", "analyst"]), async (req, res) => {
  try {
    const jobs = await UploadJob.find()
      .sort({ createdAt: -1 })
      .select("filename uploadedBy status recordCount reconciledCount startedAt completedAt");
    res.json(jobs);
  } catch (err) {
    console.error("History fetch error:", err);
    res.status(500).json({ message: "Failed to fetch reconciliation history", error: err.message });
  }
});

/**
 * 🔹 PATCH /api/reconcile/record/:id
 */
router.patch("/record/:id", async (req, res) => {
  try {
    const recordId = req.params.id;
    const updates = req.body?.updates || {};
    const changedBy = req.body?.changedBy || "Manual";

    const existing = await ReconciliationResult.findById(recordId);
    if (!existing) return res.status(404).json({ message: "Record not found" });

    const oldValue = {};
    for (const key of Object.keys(updates)) oldValue[key] = existing[key];

    const allowed = ["uploadedRecordId", "systemRecordId", "status", "differences"];
    const apply = {};
    Object.keys(updates).forEach((k) => {
      if (allowed.includes(k)) apply[k] = updates[k];
    });

    const updated = await ReconciliationResult.findByIdAndUpdate(
      recordId,
      { $set: apply },
      { new: true }
    );

    await AuditTrail.create({
      recordId,
      action: "Manual Correction",
      changedBy,
      oldValue,
      newValue: apply,
    });

    res.json({ message: "Record updated", record: updated });
  } catch (err) {
    console.error("Record update error:", err);
    res.status(500).json({ message: "Failed to update record", error: err.message });
  }
});

/**
 * 🔹 GET /api/reconcile/audit/:recordId
 */
router.get("/audit/:recordId", async (req, res) => {
  try {
    const { recordId } = req.params;
    const logs = await AuditTrail.find({ recordId }).sort({ createdAt: -1 });
    res.json(logs);
  } catch (err) {
    console.error("Audit fetch error:", err);
    res.status(500).json({ message: "Failed to fetch audit trail", error: err.message });
  }
});

export default router;
